How-To-Repeat: 1. Compile this:

#include <fcntl.h>
#include <stdio.h>
#include <sys/types.h>
#include <sys/uio.h>
#include <unistd.h>

int main(int argc, char **argv)
{
	if (argc != 2)
		return 1;

	int fd = open(argv[1], O_WRONLY);
	if (fd < 0) {
		perror("open");
		return 1;
	}

	for (;;) {
		char buf[2048];
		int ret = read(0, buf, sizeof(buf));
		if (ret < 0) {
			perror("read");
			close(fd);
			return 1;
		}
		ret = write(fd, buf, ret);
	}

	return 0;
}

2. Load if_tap, and create tap0 device.
3. cat /dev/urandom|./a.out /dev/tap0

Sooner or later it'll die.
